mapper.select:
select

from knowledge_base
where id = #{id}
  and user_id = #{ownerUserId}
  and deleted_at is null
limit 1

mapper.update:
update knowledge_base
set status = 0,
    deleted_at = #{updatedAt},
    updated_at = #{updatedAt}
where id = #{id}
  and user_id = #{ownerUserId}
  and deleted_at is null

update knowledge_base
set name = #{name},
    description = #{description},
    category = #{category},
    tags = #{tags},
    updated_at = #{updatedAt}
where id = #{id}
  and user_id = #{ownerUserId}
  and deleted_at is null
  and updated_at = #{lastKnownUpdatedAt}
